def approved_rq_set_gate(rq_set):
    # G1: C-TOTALITY - ensure rq_set is a dict
    if not isinstance(rq_set, dict):
        return {"may_proceed": False, "reason": "rq_set must be a dict"}

    # G2: approval_status must equal 'APPROVED'
    if rq_set.get("approval_status") != "APPROVED":
        return {"may_proceed": False, "reason": "approval_status must be 'APPROVED'"}

    # G3: SANCTIONED PATH - both source_research_design_id and source_revision_id must be present and non-empty
    source_research_design_id = rq_set.get("source_research_design_id")
    source_revision_id = rq_set.get("source_revision_id")

    if not source_research_design_id or not source_revision_id:
        return {"may_proceed": False, "reason": "both source_research_design_id and source_revision_id must be present and non-empty"}

    # G4: required_rqs must be a non-empty list
    required_rqs = rq_set.get("required_rqs")
    if not isinstance(required_rqs, list) or len(required_rqs) == 0:
        return {"may_proceed": False, "reason": "required_rqs must be a non-empty list"}

    # G5: at least one of resolved_intent_ref or validated_need_ref must be present and non-empty
    resolved_intent_ref = rq_set.get("resolved_intent_ref")
    validated_need_ref = rq_set.get("validated_need_ref")

    if not resolved_intent_ref and not validated_need_ref:
        return {"may_proceed": False, "reason": "at least one of resolved_intent_ref or validated_need_ref must be present and non-empty"}

    return {"may_proceed": True, "reason": "RQ set meets all gate requirements"}
